{
  "name": "Station Service Capability Assessment Platform",
  "description": "A comprehensive dashboard for assessing charging station service capabilities with multi-level drill-down (City > District > Station), dynamic temporal analysis, and operational diagnostics."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ViewState {
  S0_CITY = 'CITY',
  S1_DISTRICT = 'DISTRICT',
  S2_STATION = 'STATION'
}

export enum TimeMode {
  HISTORY = 'HISTORY',
  CURRENT = 'CURRENT',
  PREDICTION = 'PREDICTION'
}

export interface District {
  id: string;
  name: string;
  path: string; // SVG path data
  centerX: number;
  centerY: number;
  capacity: number; // Mock metric
  serviceLevel: number; // Mock metric 0-100
}

export interface Station {
  id: string;
  districtId: string;
  name: string;
  x: number; // Relative to district center
  y: number;
  type: 'Public' | 'Private' | 'Dedicated';
  status: 'Operational' | 'Faulty' | 'Offline';
  utilization: number;
}

export interface ChartDataPoint {
  time: string;
  value: number;
  value2?: number; // Optional second series
  value3?: number; // Optional third series
}

export interface AssessmentTag {
  label: string;
  type: 'danger' | 'warning' | 'info';
  evidence: string;
}

import { District, Station, TimeMode } from './types';

// Mock Shenzhen Districts (Stylized)
export const DISTRICTS: District[] = [
  { id: 'futian', name: 'Futian', path: 'M450,450 L550,450 L550,550 L450,550 Z', centerX: 500, centerY: 500, capacity: 85, serviceLevel: 92 },
  { id: 'nanshan', name: 'Nanshan', path: 'M350,450 L450,450 L450,580 L320,550 Z', centerX: 400, centerY: 500, capacity: 78, serviceLevel: 88 },
  { id: 'luohu', name: 'Luohu', path: 'M550,460 L650,440 L640,540 L550,550 Z', centerX: 600, centerY: 490, capacity: 90, serviceLevel: 85 },
  { id: 'baoan', name: 'Baoan', path: 'M200,300 L350,450 L320,550 L200,600 L150,400 Z', centerX: 250, centerY: 450, capacity: 65, serviceLevel: 75 },
  { id: 'longgang', name: 'Longgang', path: 'M550,300 L750,280 L800,450 L650,440 L550,460 Z', centerX: 680, centerY: 380, capacity: 70, serviceLevel: 80 },
  { id: 'yantian', name: 'Yantian', path: 'M650,440 L800,450 L780,500 L640,540 Z', centerX: 720, centerY: 480, capacity: 88, serviceLevel: 90 },
];

// Generate Mock Stations
export const generateStations = (districtId: string): Station[] => {
  const stations: Station[] = [];
  const count = 10 + Math.floor(Math.random() * 10);
  for (let i = 0; i < count; i++) {
    stations.push({
      id: `${districtId}-s-${i}`,
      districtId,
      name: `${districtId.charAt(0).toUpperCase() + districtId.slice(1)} Station #${i + 1}`,
      x: (Math.random() - 0.5) * 80, // Spread around district center
      y: (Math.random() - 0.5) * 80,
      type: Math.random() > 0.7 ? 'Dedicated' : Math.random() > 0.4 ? 'Public' : 'Private',
      status: Math.random() > 0.9 ? 'Offline' : Math.random() > 0.85 ? 'Faulty' : 'Operational',
      utilization: Math.floor(Math.random() * 100),
    });
  }
  return stations;
};

// Mock Chart Data Generators
export const generateTimeSeries = (points: number, base: number, variance: number) => {
  return Array.from({ length: points }, (_, i) => ({
    time: `${String(Math.floor(i / 4)).padStart(2, '0')}:${String((i % 4) * 15).padStart(2, '0')}`,
    value: Math.max(0, base + Math.sin(i * 0.2) * variance + (Math.random() - 0.5) * variance),
    value2: Math.max(0, base * 0.8 + Math.cos(i * 0.2) * variance), // Comparative series
    value3: Math.max(0, base * 1.2 - Math.sin(i * 0.2) * (variance / 2)), // Prediction/Limits
  }));
};

export const TIME_MODES = [
  { id: TimeMode.HISTORY, label: 'Historical' },
  { id: TimeMode.CURRENT, label: 'Real-time' },
  { id: TimeMode.PREDICTION, label: 'Prediction' },
];

export const PIE_DATA_POWER = [
  { name: 'Fast (DC)', value: 400 },
  { name: 'Super (HPC)', value: 150 },
  { name: 'Slow (AC)', value: 300 },
];

export const PIE_DATA_FUNCTION = [
  { name: 'Public', value: 350 },
  { name: 'Dedicated', value: 200 },
  { name: 'Residential', value: 150 },
  { name: 'Highway', value: 80 },
  { name: 'Logistic', value: 50 },
  { name: 'Swap', value: 20 },
];

export const COLORS = ['#0ea5e9', '#22c55e', '#eab308', '#f43f5e', '#8b5cf6', '#d946ef'];

import React, { useState, useEffect } from 'react';
import { Wifi, Sun, CloudRain } from 'lucide-react';

const Header: React.FC = () => {
  const [time, setTime] = useState(new Date());

  useEffect(() => {
    const timer = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  return (
    <header className="h-16 bg-slate-900/90 border-b border-slate-700 flex items-center justify-between px-6 backdrop-blur-md z-50 select-none">
      <div className="flex items-center gap-4">
        <h1 className="text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-cyan-400 to-blue-500 tracking-wider">
          STATION SERVICE CAPABILITY ASSESSMENT
        </h1>
        <div className="px-2 py-0.5 rounded bg-emerald-500/10 border border-emerald-500/30 text-emerald-400 text-xs font-mono flex items-center gap-2">
          <span className="relative flex h-2 w-2">
            <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-emerald-400 opacity-75"></span>
            <span className="relative inline-flex rounded-full h-2 w-2 bg-emerald-500"></span>
          </span>
          REAL-TIME
        </div>
      </div>

      <div className="flex items-center gap-6 text-slate-400 font-mono text-sm">
        <div className="flex items-center gap-2">
          <Sun className="w-4 h-4 text-amber-400" />
          <span>28°C Clear</span>
        </div>
        <div className="h-4 w-px bg-slate-700"></div>
        <div>{time.toLocaleDateString()}</div>
        <div className="text-slate-200 font-bold">{time.toLocaleTimeString()}</div>
        <div className="h-4 w-px bg-slate-700"></div>
        <div className="flex items-center gap-2 text-xs">
          <Wifi className="w-3 h-3 text-cyan-500" />
          <span>Data: 30ms</span>
        </div>
      </div>
    </header>
  );
};

export default Header;

import React from 'react';

interface StatCardProps {
  title: string;
  value: string | number;
  unit?: string;
  trend?: number; // percentage
  icon?: React.ReactNode;
  variant?: 'default' | 'alert' | 'success';
}

const StatCard: React.FC<StatCardProps> = ({ title, value, unit, trend, icon, variant = 'default' }) => {
  const borderColor = 
    variant === 'alert' ? 'border-rose-500/50' : 
    variant === 'success' ? 'border-emerald-500/50' : 
    'border-slate-700';

  const bgGradient = 
    variant === 'alert' ? 'bg-gradient-to-br from-rose-900/20 to-slate-800' :
    variant === 'success' ? 'bg-gradient-to-br from-emerald-900/20 to-slate-800' :
    'bg-slate-800/50';

  return (
    <div className={`p-4 rounded-lg border ${borderColor} ${bgGradient} backdrop-blur-sm shadow-sm relative overflow-hidden group`}>
      <div className="flex justify-between items-start mb-2">
        <span className="text-slate-400 text-xs font-medium uppercase tracking-wider">{title}</span>
        {icon && <span className="text-slate-500 group-hover:text-cyan-400 transition-colors">{icon}</span>}
      </div>
      <div className="flex items-baseline gap-2">
        <span className="text-2xl font-bold text-white font-mono">{value}</span>
        {unit && <span className="text-xs text-slate-500">{unit}</span>}
      </div>
      {trend !== undefined && (
        <div className={`text-xs mt-1 ${trend > 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
          {trend > 0 ? '↑' : '↓'} {Math.abs(trend)}% vs last hr
        </div>
      )}
      {/* Decorative accent */}
      <div className="absolute bottom-0 left-0 w-full h-0.5 bg-gradient-to-r from-transparent via-cyan-500/30 to-transparent opacity-0 group-hover:opacity-100 transition-opacity" />
    </div>
  );
};

export default StatCard;

import React from 'react';
import { ViewState, TimeMode, generateTimeSeries, AssessmentTag } from '../types';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip as ReTooltip, ResponsiveContainer, LineChart, Line, Legend } from 'recharts';
import { AlertCircle, TrendingUp, Cpu, Battery, FileText } from 'lucide-react';

interface RightPanelProps {
  viewState: ViewState;
  timeMode: TimeMode;
}

const RightPanel: React.FC<RightPanelProps> = ({ viewState, timeMode }) => {
  // Generate dummy data based on view state to simulate dynamism
  const dataPoints = 24;
  const gridCapacityData = generateTimeSeries(dataPoints, 80, 15);
  const pileStatusData = generateTimeSeries(dataPoints, 5, 2);

  const isStation = viewState === ViewState.S2_STATION;

  // Render Assessment Tags (Only for S2)
  const renderAssessmentTags = () => {
    const tags: AssessmentTag[] = [
      { label: 'Grid Overload Risk', type: 'danger', evidence: 'Grid load > 92% during 18:00-20:00' },
      { label: 'High Utilization', type: 'info', evidence: 'Daily utilization avg 78%' },
      { label: 'Maintenance Due', type: 'warning', evidence: '3 piles offline > 48hrs' },
    ];

    return (
      <div className="bg-slate-800 p-4 rounded-xl border border-slate-600 mb-4">
        <h3 className="text-sm font-bold text-white mb-3 flex items-center gap-2">
          <FileText size={16} className="text-cyan-400"/> AI Assessment Diagnosis
        </h3>
        <div className="space-y-3">
          {tags.map((tag, i) => (
            <div key={i} className="flex flex-col gap-1 bg-slate-900/50 p-2 rounded border-l-2 border-slate-700 hover:bg-slate-700/50 transition-colors">
              <div className="flex items-center justify-between">
                <span className={`text-xs font-bold px-2 py-0.5 rounded ${
                  tag.type === 'danger' ? 'bg-rose-500/20 text-rose-400' :
                  tag.type === 'warning' ? 'bg-amber-500/20 text-amber-400' :
                  'bg-blue-500/20 text-blue-400'
                }`}>
                  {tag.label}
                </span>
              </div>
              <p className="text-[10px] text-slate-400 pl-1">Evidence: {tag.evidence}</p>
            </div>
          ))}
        </div>
      </div>
    );
  };

  return (
    <div className="flex flex-col gap-4 h-full overflow-y-auto pl-2">
      <div className="mb-2">
        <h2 className="text-lg font-semibold text-cyan-100 border-r-4 border-blue-500 pr-3 text-right">
          {isStation ? 'Station Diagnostics' : 'Dynamic Analysis'}
        </h2>
        <p className="text-xs text-slate-400 text-right mt-1">
          {timeMode === TimeMode.PREDICTION ? 'Predictive Analytics (Next 24h)' : 'Real-time Monitoring'}
        </p>
      </div>

      {/* S2: Diagnostic Tags */}
      {isStation && renderAssessmentTags()}

      {/* Grid Capacity Chart (Common to all, but detailed in S2) */}
      <div className="bg-slate-800/40 p-4 rounded-xl border border-slate-700/50 flex-1 min-h-[200px]">
        <h3 className="text-sm font-medium text-slate-300 mb-2 flex items-center gap-2">
          <Cpu size={14} /> 
          {isStation ? 'L2 Grid Remaining Capacity' : 'Regional Grid Load'}
        </h3>
        <div className="h-40">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={gridCapacityData}>
              <defs>
                <linearGradient id="colorGrid" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#0ea5e9" stopOpacity={0.3}/>
                  <stop offset="95%" stopColor="#0ea5e9" stopOpacity={0}/>
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
              <XAxis dataKey="time" tick={{fontSize: 10}} stroke="#64748b" interval={3} />
              <YAxis tick={{fontSize: 10}} stroke="#64748b" />
              <ReTooltip 
                contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#f8fafc' }}
              />
              <Area type="monotone" dataKey="value" stroke="#0ea5e9" fillOpacity={1} fill="url(#colorGrid)" />
              {timeMode === TimeMode.PREDICTION && (
                 <Area type="monotone" dataKey="value3" stroke="#6366f1" strokeDasharray="5 5" fill="none" name="Prediction" />
              )}
            </AreaChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Pile Availability / Issues */}
      <div className="bg-slate-800/40 p-4 rounded-xl border border-slate-700/50 flex-1 min-h-[200px]">
        <h3 className="text-sm font-medium text-slate-300 mb-2 flex items-center gap-2">
          <AlertCircle size={14} /> 
          {isStation ? 'Station Pile Availability' : 'Bad/Offline Pile Trend'}
        </h3>
        <div className="h-40">
           <ResponsiveContainer width="100%" height="100%">
            <LineChart data={pileStatusData}>
              <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
              <XAxis dataKey="time" tick={{fontSize: 10}} stroke="#64748b" interval={3} />
              <YAxis tick={{fontSize: 10}} stroke="#64748b" />
              <ReTooltip 
                contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#f8fafc' }}
              />
              <Legend iconType="circle" wrapperStyle={{fontSize: '10px'}}/>
              <Line type="step" dataKey="value" name="Offline" stroke="#f43f5e" dot={false} strokeWidth={2} />
              <Line type="step" dataKey="value2" name="Occupied" stroke="#eab308" dot={false} strokeWidth={2} />
            </LineChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Orders / Flow (Only S2 or S1) */}
      <div className="bg-slate-800/40 p-4 rounded-xl border border-slate-700/50 flex-1 min-h-[200px]">
        <h3 className="text-sm font-medium text-slate-300 mb-2 flex items-center gap-2">
          <TrendingUp size={14} /> 
          {isStation ? 'Charging Orders Flow' : 'Regional Charging Demand'}
        </h3>
         <div className="h-40">
           <ResponsiveContainer width="100%" height="100%">
            <AreaChart data={gridCapacityData}> 
              <defs>
                <linearGradient id="colorFlow" x1="0" y1="0" x2="0" y2="1">
                  <stop offset="5%" stopColor="#10b981" stopOpacity={0.3}/>
                  <stop offset="95%" stopColor="#10b981" stopOpacity={0}/>
                </linearGradient>
              </defs>
              <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
              <XAxis dataKey="time" tick={{fontSize: 10}} stroke="#64748b" interval={3} />
              <YAxis tick={{fontSize: 10}} stroke="#64748b" />
              <ReTooltip contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155' }} />
              <Area type="monotone" dataKey="value" stroke="#10b981" fill="url(#colorFlow)" />
            </AreaChart>
          </ResponsiveContainer>
        </div>
      </div>

    </div>
  );
};

export default RightPanel;

import React from 'react';
import { TimeMode, TIME_MODES } from '../types';
import { Play, Pause, SkipBack, SkipForward } from 'lucide-react';

interface TimelineProps {
  timeMode: TimeMode;
  setTimeMode: (mode: TimeMode) => void;
  timelineValue: number;
  setTimelineValue: (val: number) => void;
}

const Timeline: React.FC<TimelineProps> = ({ timeMode, setTimeMode, timelineValue, setTimelineValue }) => {

  const formatTime = (val: number) => {
    const hours = Math.floor(val / 4);
    const minutes = (val % 4) * 15;
    return `${String(hours).padStart(2, '0')}:${String(minutes).padStart(2, '0')}`;
  };

  return (
    <div className="absolute bottom-6 left-6 right-6 bg-slate-900/80 border border-slate-700 backdrop-blur-md rounded-xl p-4 flex flex-col gap-3 z-30 shadow-2xl">

      {/* Top Controls: Mode Switcher & Playback */}
      <div className="flex justify-between items-center">
        <div className="flex bg-slate-800 rounded-lg p-1 border border-slate-700">
          {TIME_MODES.map((mode) => (
            <button
              key={mode.id}
              onClick={() => setTimeMode(mode.id)}
              className={`px-4 py-1.5 text-xs font-medium rounded-md transition-all ${
                timeMode === mode.id
                  ? 'bg-cyan-600 text-white shadow-lg'
                  : 'text-slate-400 hover:text-white hover:bg-slate-700'
              }`}
            >
              {mode.label}
            </button>
          ))}
        </div>

        <div className="flex items-center gap-4 text-slate-300">
           <span className="font-mono text-xl font-bold text-cyan-400 min-w-[60px]">{formatTime(timelineValue)}</span>
           <div className="flex gap-2">
             <button className="p-1.5 hover:bg-slate-700 rounded text-slate-400 hover:text-white"><SkipBack size={16}/></button>
             <button className="p-1.5 bg-cyan-600 hover:bg-cyan-500 rounded-full text-white shadow-lg shadow-cyan-900/50"><Play size={16} fill="currentColor" /></button>
             <button className="p-1.5 hover:bg-slate-700 rounded text-slate-400 hover:text-white"><SkipForward size={16}/></button>
           </div>
        </div>
      </div>

      {/* Slider */}
      <div className="relative h-6 flex items-center group">
         {/* Ticks */}
         <div className="absolute top-1/2 -translate-y-1/2 w-full flex justify-between px-1 pointer-events-none">
            {[0, 24, 48, 72, 96].map((tick) => (
               <div key={tick} className="h-2 w-px bg-slate-600"></div>
            ))}
         </div>
         <input
           type="range"
           min="0"
           max="96"
           value={timelineValue}
           onChange={(e) => setTimelineValue(parseInt(e.target.value))}
           className="w-full h-1.5 bg-slate-700 rounded-lg appearance-none cursor-pointer accent-cyan-500 hover:accent-cyan-400 z-10"
         />
      </div>

    </div>
  );
};

export default Timeline;

import React, { useMemo, useState } from 'react';
import { ViewState, District, Station, TimeMode } from '../types';
import { DISTRICTS, generateStations } from '../constants';
import { ArrowLeft } from 'lucide-react';

interface MapComponentProps {
  viewState: ViewState;
  selectedDistrictId: string | null;
  selectedStationId: string | null;
  timeMode: TimeMode;
  onDistrictClick: (id: string) => void;
  onStationClick: (station: Station) => void;
  onBack: () => void;
}

const MapComponent: React.FC<MapComponentProps> = ({
  viewState,
  selectedDistrictId,
  selectedStationId,
  timeMode,
  onDistrictClick,
  onStationClick,
  onBack
}) => {

  // Memoize stations for the selected district so they don't regenerate on every render
  const currentStations = useMemo(() => {
    if (!selectedDistrictId) return [];
    return generateStations(selectedDistrictId);
  }, [selectedDistrictId]);

  // Determine Map Transform based on State
  const getTransform = () => {
    if (viewState === ViewState.S0_CITY) return 'translate(0, 0) scale(1)';

    // Find district center to zoom into
    const district = DISTRICTS.find(d => d.id === selectedDistrictId);
    if (!district) return 'translate(0,0) scale(1)';

    // Simple zoom logic: Translate center to (500, 500) and scale up
    const scale = 3.5;
    const tx = 500 - district.centerX * scale;
    const ty = 500 - district.centerY * scale;

    return `translate(${tx}px, ${ty}px) scale(${scale})`;
  };

  // Dynamic Color based on TimeMode (Mock effect)
  const getDistrictColor = (district: District) => {
    if (timeMode === TimeMode.PREDICTION) {
       return district.capacity < 70 ? '#f43f5e' : '#3b82f6'; // Red if capacity low in future
    }
    // Gradient based on mock capacity
    const opacity = 0.3 + (district.capacity / 200);
    return `rgba(14, 165, 233, ${opacity})`; 
  };

  return (
    <div className="relative w-full h-full bg-slate-900 overflow-hidden rounded-xl border border-slate-700 shadow-inner group">

      {/* Grid Background Effect */}
      <div className="absolute inset-0 opacity-10 pointer-events-none" 
           style={{ backgroundImage: 'linear-gradient(#334155 1px, transparent 1px), linear-gradient(90deg, #334155 1px, transparent 1px)', backgroundSize: '40px 40px' }}>
      </div>

      {/* Back Button Overlay */}
      {viewState !== ViewState.S0_CITY && (
        <button 
          onClick={onBack}
          className="absolute top-4 left-4 z-40 bg-slate-800/90 text-white px-4 py-2 rounded-lg border border-slate-600 hover:bg-cyan-600 hover:border-cyan-500 transition-all flex items-center gap-2 shadow-lg"
        >
          <ArrowLeft size={16} />
          Back to {viewState === ViewState.S2_STATION ? 'District' : 'City'}
        </button>
      )}

      {/* SVG Map Container */}
      <svg className="w-full h-full" viewBox="0 0 1000 1000" preserveAspectRatio="xMidYMid slice">
        <g 
           style={{ transform: getTransform(), transition: 'transform 1s cubic-bezier(0.25, 1, 0.5, 1)' }}
           className="origin-top-left"
        >

          {/* Render Districts */}
          {DISTRICTS.map((district) => {
            const isSelected = selectedDistrictId === district.id;
            const isDimmed = viewState !== ViewState.S0_CITY && !isSelected;

            return (
              <g key={district.id} 
                 onClick={(e) => {
                   e.stopPropagation();
                   if (viewState === ViewState.S0_CITY) onDistrictClick(district.id);
                 }}
                 className={`${viewState === ViewState.S0_CITY ? 'cursor-pointer hover:opacity-80' : ''}`}
              >
                 <path
                    d={district.path}
                    fill={getDistrictColor(district)}
                    stroke="#0ea5e9"
                    strokeWidth={viewState === ViewState.S0_CITY ? 2 : 1}
                    className={`transition-all duration-500 ${isDimmed ? 'opacity-10 grayscale' : 'opacity-100'}`}
                 />
                 {/* District Label (Only in S0) */}
                 {viewState === ViewState.S0_CITY && (
                   <text x={district.centerX} y={district.centerY} textAnchor="middle" fill="white" fontSize="14" fontWeight="bold" className="pointer-events-none drop-shadow-md">
                     {district.name}
                   </text>
                 )}
              </g>
            );
          })}

          {/* Render Stations (Only visible in S1/S2) */}
          {(viewState === ViewState.S1_DISTRICT || viewState === ViewState.S2_STATION) && selectedDistrictId && (
             <g>
                {currentStations.map((station) => {
                  const isActive = station.id === selectedStationId;
                  const district = DISTRICTS.find(d => d.id === selectedDistrictId);
                  if (!district) return null;

                  return (
                    <g key={station.id} 
                       transform={`translate(${district.centerX + station.x}, ${district.centerY + station.y})`}
                       onClick={(e) => {
                         e.stopPropagation();
                         onStationClick(station);
                       }}
                       className="cursor-pointer"
                    >
                       {/* Pulse Effect for selected */}
                       {isActive && (
                         <circle r="6" fill="none" stroke="#fff" strokeWidth="0.5" className="animate-ping" />
                       )}

                       {/* Station Dot */}
                       <circle 
                          r={isActive ? 3 : 1.5} 
                          fill={station.status === 'Operational' ? '#10b981' : station.status === 'Faulty' ? '#f59e0b' : '#64748b'} 
                          stroke={isActive ? '#fff' : 'none'}
                          strokeWidth={0.5}
                          className="transition-all duration-300 hover:r-4"
                       />
                    </g>
                  );
                })}
             </g>
          )}

        </g>
      </svg>

      {/* Legend Overlay */}
