import React, { useMemo } from 'react';
import { ViewState, District, Station, TimeMode } from '../types';
import { DISTRICTS, generateStations, TIME_MODES } from '../constants';
import { ArrowLeft, Maximize2, Layers } from 'lucide-react';

interface MapComponentProps {
  viewState: ViewState;
  selectedDistrictId: string | null;
  selectedStationId: string | null;
  timeMode: TimeMode;
  setTimeMode: (mode: TimeMode) => void;
  onDistrictClick: (id: string) => void;
  onStationClick: (station: Station) => void;
  onBack: () => void;
}

const MapComponent: React.FC<MapComponentProps> = ({
  viewState,
  selectedDistrictId,
  selectedStationId,
  timeMode,
  setTimeMode,
  onDistrictClick,
  onStationClick,
  onBack
}) => {

  // Memoize stations
  const currentStations = useMemo(() => {
    if (!selectedDistrictId) return [];
    return generateStations(selectedDistrictId);
  }, [selectedDistrictId]);

  // Determine Map Transform
  const getTransform = () => {
    if (viewState === ViewState.S0_CITY) return 'translate(50, 0) scale(0.9)'; // Fit Shenzhen roughly

    const district = DISTRICTS.find(d => d.id === selectedDistrictId);
    if (!district) return 'translate(0,0) scale(1)';

    const scale = 3;
    const tx = 500 - district.centerX * scale;
    const ty = 500 - district.centerY * scale;

    return `translate(${tx}px, ${ty}px) scale(${scale})`;
  };

  // Dynamic Color
  const getDistrictColor = (district: District) => {
    if (timeMode === TimeMode.PREDICTION) {
       return district.capacity < 70 ? '#be123c' : '#1d4ed8'; // Red/Blue for future
    }
    // Gradient based on mock capacity
    const opacity = 0.2 + (district.capacity / 150);
    // Use slightly different hues for adjacent visual separation if desired, but sticking to cyan theme
    return `rgba(6, 182, 212, ${opacity})`; 
  };

  return (
    <div className="relative w-full h-full bg-slate-900 overflow-hidden rounded-xl border border-slate-700 shadow-inner group">

      {/* --- TOP TIME WINDOW OVERLAY (Requirement) --- */}
      <div className="absolute top-6 left-1/2 -translate-x-1/2 z-40 bg-slate-900/90 border border-slate-600 rounded-full p-1 shadow-2xl flex items-center backdrop-blur-md">
         {TIME_MODES.map((mode) => (
            <button
              key={mode.id}
              onClick={() => setTimeMode(mode.id)}
              className={`px-6 py-2 text-sm font-bold rounded-full transition-all duration-300 ${
                timeMode === mode.id
                  ? 'bg-gradient-to-r from-cyan-600 to-blue-600 text-white shadow-lg scale-105'
                  : 'text-slate-400 hover:text-white hover:bg-slate-800'
              }`}
            >
              {mode.label}
            </button>
         ))}
      </div>

      {/* Grid Background */}
      <div className="absolute inset-0 opacity-20 pointer-events-none" 
           style={{ backgroundImage: 'linear-gradient(#1e293b 1px, transparent 1px), linear-gradient(90deg, #1e293b 1px, transparent 1px)', backgroundSize: '50px 50px' }}>
      </div>

      {/* Back Button */}
      {viewState !== ViewState.S0_CITY && (
        <button 
          onClick={onBack}
          className="absolute top-6 left-6 z-40 bg-slate-800/90 text-white px-4 py-2 rounded-lg border border-slate-600 hover:bg-cyan-600 hover:border-cyan-500 transition-all flex items-center gap-2 shadow-lg"
        >
          <ArrowLeft size={16} />
          返回 {viewState === ViewState.S2_STATION ? '区域详情' : '全市总览'}
        </button>
      )}

      {/* SVG Map */}
      <svg className="w-full h-full" viewBox="0 0 1000 600" preserveAspectRatio="xMidYMid meet">
        <defs>
           <filter id="glow" x="-20%" y="-20%" width="140%" height="140%">
             <feGaussianBlur stdDeviation="3" result="blur" />
             <feComposite in="SourceGraphic" in2="blur" operator="over" />
           </filter>
        </defs>

        <g 
           style={{ transform: getTransform(), transition: 'transform 1.2s cubic-bezier(0.25, 1, 0.5, 1)' }}
           className="origin-center"
        >

          {/* Render Districts */}
          {DISTRICTS.map((district) => {
            const isSelected = selectedDistrictId === district.id;
            const isDimmed = viewState !== ViewState.S0_CITY && !isSelected;

            return (
              <g key={district.id} 
                 onClick={(e) => {
                   e.stopPropagation();
                   if (viewState === ViewState.S0_CITY) onDistrictClick(district.id);
                 }}
                 className={`${viewState === ViewState.S0_CITY ? 'cursor-pointer' : ''} transition-opacity duration-500 ${isDimmed ? 'opacity-20 pointer-events-none' : 'opacity-100'}`}
              >
                 <path
                    d={district.path}
                    fill={getDistrictColor(district)}
                    stroke={isSelected ? "#fff" : "#0ea5e9"}
                    strokeWidth={isSelected ? 3 : 1}
                    filter={isSelected ? "url(#glow)" : ""}
                    className={`transition-all duration-300 hover:fill-cyan-600/60`}
                 />

                 {/* District Label */}
                 {viewState === ViewState.S0_CITY && (
                   <g className="pointer-events-none">
                     <text x={district.centerX} y={district.centerY} textAnchor="middle" fill="white" fontSize="14" fontWeight="bold" className="drop-shadow-md select-none">
                       {district.name}
                     </text>
                     <text x={district.centerX} y={district.centerY + 14} textAnchor="middle" fill="#94a3b8" fontSize="9" className="select-none">
                       容量: {district.capacity}%
                     </text>
                   </g>
                 )}
              </g>
            );
          })}

          {/* Render Stations (S1/S2) */}
          {(viewState === ViewState.S1_DISTRICT || viewState === ViewState.S2_STATION) && selectedDistrictId && (
             <g className="animate-[fadeIn_0.5s_ease-in]">
                {currentStations.map((station) => {
                  const isActive = station.id === selectedStationId;
                  const district = DISTRICTS.find(d => d.id === selectedDistrictId);
                  if (!district) return null;

                  return (
                    <g key={station.id} 
                       transform={`translate(${district.centerX + station.x}, ${district.centerY + station.y})`}
                       onClick={(e) => {
                         e.stopPropagation();
                         onStationClick(station);
                       }}
                       className="cursor-pointer group/station"
                    >
                       {/* Pulse Effect for selected */}
                       {isActive && (
                         <>
                           <circle r="15" fill="none" stroke="#fff" strokeWidth="0.5" className="animate-ping opacity-50" />
                           <circle r="8" fill="rgba(255,255,255,0.2)" />
                         </>
                       )}

                       {/* Station Dot */}
                       <circle 
                          r={isActive ? 4 : 2} 
                          fill={station.status === 'Operational' ? '#34d399' : station.status === 'Faulty' ? '#fbbf24' : '#94a3b8'} 
                          stroke={isActive ? '#fff' : '#0f172a'}
                          strokeWidth={0.5}
                          className="transition-all duration-200 group-hover/station:r-4 group-hover/station:stroke-white"
                       />

                       {/* Hover Label (Simple) */}
                       {isActive && (
                          <g transform="translate(0, -12)">
                             <rect x="-40" y="-20" width="80" height="18" rx="4" fill="#0f172a" fillOpacity="0.8" />
                             <text x="0" y="-8" textAnchor="middle" fill="white" fontSize="8">{station.name}</text>
                          </g>
                       )}
                    </g>
                  );
                })}
             </g>
          )}

        </g>
      </svg>

      {/* Legend Overlay */}
      <div className="absolute top-6 right-6 bg-slate-900/80 p-4 rounded-xl border border-slate-700 text-xs text-slate-300 backdrop-blur pointer-events-none select-none shadow-xl">
        <h4 className="mb-3 font-bold text-white border-b border-slate-700 pb-2 flex items-center gap-2">
           <Layers size={14}/> 图例说明
        </h4>
        <div className="space-y-2">
          <div className="flex items-center gap-2"><span className="w-2.5 h-2.5 rounded-full bg-cyan-500/50 border border-cyan-400"></span> 区域容量充足</div>
          <div className="flex items-center gap-2"><span className="w-2.5 h-2.5 rounded-full bg-cyan-500/20 border border-cyan-800"></span> 区域容量空闲</div>
          <div className="h-px bg-slate-700 my-1"></div>
          <div className="flex items-center gap-2"><span className="w-2.5 h-2.5 rounded-full bg-emerald-400"></span> 场站正常</div>
          <div className="flex items-center gap-2"><span className="w-2.5 h-2.5 rounded-full bg-amber-400"></span> 场站故障</div>
          <div className="flex items-center gap-2"><span className="w-2.5 h-2.5 rounded-full bg-slate-400"></span> 场站离线</div>
        </div>
      </div>

    </div>
  );
};

export default MapComponent;

import React, { useState } from 'react';
import Header from './components/Header';
import LeftPanel from './components/LeftPanel';
import RightPanel from './components/RightPanel';
import MapComponent from './components/MapComponent';
import Timeline from './components/Timeline';
import { ViewState, TimeMode, Station } from './types';

const App: React.FC = () => {
  // State Machine
  const [viewState, setViewState] = useState<ViewState>(ViewState.S0_CITY);
  const [selectedDistrictId, setSelectedDistrictId] = useState<string | null>(null);
  const [selectedStation, setSelectedStation] = useState<Station | null>(null);

  // Time Control State
  const [timeMode, setTimeMode] = useState<TimeMode>(TimeMode.CURRENT);
  const [timelineValue, setTimelineValue] = useState<number>(48); // 12:00 PM

  // Handlers
  const handleDistrictClick = (districtId: string) => {
    setSelectedDistrictId(districtId);
    setViewState(ViewState.S1_DISTRICT);
  };

  const handleStationClick = (station: Station) => {
    setSelectedStation(station);
    setViewState(ViewState.S2_STATION);
  };

  const handleBack = () => {
    if (viewState === ViewState.S2_STATION) {
      setViewState(ViewState.S1_DISTRICT);
      setSelectedStation(null);
    } else if (viewState === ViewState.S1_DISTRICT) {
      setViewState(ViewState.S0_CITY);
      setSelectedDistrictId(null);
    }
  };

  return (
    <div className="flex flex-col h-screen bg-slate-950 text-slate-200 overflow-hidden font-sans selection:bg-cyan-500/30">
      <Header />

      <main className="flex-1 grid grid-cols-12 gap-5 p-5 overflow-hidden h-[calc(100vh-64px)]">

        {/* Left Column: Statistics */}
        <section className="col-span-3 bg-slate-900/60 rounded-2xl border border-slate-800 p-4 h-full flex flex-col backdrop-blur-xl shadow-2xl">
          <LeftPanel 
             viewState={viewState} 
             selectedDistrictId={selectedDistrictId} 
             selectedStation={selectedStation} 
          />
        </section>

        {/* Center Column: Map & Timeline */}
        <section className="col-span-6 flex flex-col relative h-full rounded-2xl overflow-hidden border border-slate-800 shadow-2xl bg-black/20">
           {/* Map includes Top Time Window Switcher */}
           <MapComponent 
             viewState={viewState}
             selectedDistrictId={selectedDistrictId}
             selectedStationId={selectedStation?.id || null}
             timeMode={timeMode}
             setTimeMode={setTimeMode}
             onDistrictClick={handleDistrictClick}
             onStationClick={handleStationClick}
             onBack={handleBack}
           />

           {/* Bottom Timeline */}
           <Timeline 
             timelineValue={timelineValue}
             setTimelineValue={setTimelineValue}
           />
        </section>

        {/* Right Column: Dynamic Analysis */}
        <section className="col-span-3 bg-slate-900/60 rounded-2xl border border-slate-800 p-4 h-full flex flex-col backdrop-blur-xl shadow-2xl">
           <RightPanel viewState={viewState} timeMode={timeMode} />
        </section>

      </main>
    </div>
  );
};

