// Helper to create a rough polygon around a center
const createPolygon = (center: [number, number], radiusDeg: number = 0.04): [number, number][] => {
  const [lat, lng] = center;
  return [
    [lat + radiusDeg * 0.7, lng - radiusDeg], // NW
    [lat + radiusDeg, lng + radiusDeg * 0.5], // NE
    [lat - radiusDeg * 0.5, lng + radiusDeg], // SE
    [lat - radiusDeg, lng - radiusDeg * 0.8], // SW
  ];
};

