import React, { useEffect, useRef, useMemo } from 'react';
import { ViewState, District, Station, TimeMode } from '../types';
import { DISTRICTS, generateStations, TIME_MODES } from '../constants';
import { ArrowLeft, Layers } from 'lucide-react';
import L from 'leaflet';

interface MapComponentProps {
  viewState: ViewState;
  selectedDistrictId: string | null;
  selectedStationId: string | null;
  timeMode: TimeMode;
  setTimeMode: (mode: TimeMode) => void;
  onDistrictClick: (id: string) => void;
  onStationClick: (station: Station) => void;
  onBack: () => void;
}

const MapComponent: React.FC<MapComponentProps> = ({
  viewState,
  selectedDistrictId,
  selectedStationId,
  timeMode,
  setTimeMode,
  onDistrictClick,
  onStationClick,
  onBack
}) => {
  const mapContainer = useRef<HTMLDivElement>(null);
  const mapInstance = useRef<L.Map | null>(null);
  const districtLayerRef = useRef<L.LayerGroup | null>(null);
  const stationLayerRef = useRef<L.LayerGroup | null>(null);

  // Memoize stations
  const currentStations = useMemo(() => {
    if (!selectedDistrictId) return [];
    return generateStations(selectedDistrictId);
  }, [selectedDistrictId]);

  // Initialize Map
  useEffect(() => {
    if (!mapContainer.current) return;
    if (mapInstance.current) return;

    const map = L.map(mapContainer.current, {
      center: [22.6, 114.1], // Center of Shenzhen
      zoom: 10,
      zoomControl: false,
      attributionControl: false
    });

    // Dark Matter Tiles
    L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
      maxZoom: 19
    }).addTo(map);

    // Layer Groups
    const districtLayer = L.layerGroup().addTo(map);
    const stationLayer = L.layerGroup().addTo(map);

    districtLayerRef.current = districtLayer;
    stationLayerRef.current = stationLayer;
    mapInstance.current = map;

    return () => {
      map.remove();
      mapInstance.current = null;
    };
  }, []);

  // Handle District Polygons (S0)
  useEffect(() => {
    if (!mapInstance.current || !districtLayerRef.current) return;
    const layerGroup = districtLayerRef.current;

    // Clear districts if we are deep in S1/S2? 
    // Actually, good UX is to keep them but fade them out, or just show the selected one.
    // For simplicity: Show all in S0, Only selected boundary in S1/S2 (or none).

    layerGroup.clearLayers();

    if (viewState === ViewState.S0_CITY) {
      DISTRICTS.forEach(district => {
        const color = timeMode === TimeMode.PREDICTION 
          ? (district.capacity < 70 ? '#be123c' : '#1d4ed8')
          : `rgba(6, 182, 212, ${0.4 + (district.capacity / 200)})`; // Dynamic cyan intensity

        const polygon = L.polygon(district.coordinates, {
          color: '#0ea5e9',
          weight: 2,
          fillColor: color,
          fillOpacity: 0.4
        });

        polygon.on('click', (e) => {
          L.DomEvent.stopPropagation(e);
          onDistrictClick(district.id);
        });

        polygon.on('mouseover', () => {
          polygon.setStyle({ weight: 4, fillOpacity: 0.6 });
        });
        polygon.on('mouseout', () => {
          polygon.setStyle({ weight: 2, fillOpacity: 0.4 });
        });

        // Simple Tooltip
        polygon.bindTooltip(`
          <div class="text-center">
            <div class="font-bold text-sm">${district.name}</div>
            <div class="text-xs">容量: ${district.capacity}%</div>
          </div>
        `, {
          permanent: true,
          direction: 'center',
          className: 'bg-transparent border-0 text-white shadow-none font-bold'
        });

        layerGroup.addLayer(polygon);
      });
    } else if (selectedDistrictId) {
       // Draw only the selected district boundary for context, but darker
       const district = DISTRICTS.find(d => d.id === selectedDistrictId);
       if (district) {
         const polygon = L.polygon(district.coordinates, {
            color: '#334155',
            weight: 2,
            fillColor: '#000',
            fillOpacity: 0.1,
            interactive: false
         });
         layerGroup.addLayer(polygon);
       }
    }

  }, [viewState, timeMode, selectedDistrictId, onDistrictClick]);

  // Handle Station Markers (S1/S2)
  useEffect(() => {
    if (!mapInstance.current || !stationLayerRef.current) return;
    const layerGroup = stationLayerRef.current;
    layerGroup.clearLayers();

    if (viewState === ViewState.S1_DISTRICT || viewState === ViewState.S2_STATION) {
      currentStations.forEach(station => {
        const isSelected = station.id === selectedStationId;

        const color = station.status === 'Operational' ? '#34d399' : station.status === 'Faulty' ? '#fbbf24' : '#94a3b8';

        // Custom Icon
        const iconHtml = `
          <div class="relative flex items-center justify-center">
            ${isSelected ? '<div class="absolute w-8 h-8 rounded-full border border-white animate-ping opacity-50"></div>' : ''}
            <div class="w-3 h-3 rounded-full border border-slate-900 shadow-sm" style="background-color: ${color}; transform: scale(${isSelected ? 1.5 : 1}); transition: transform 0.2s;"></div>
          </div>
        `;

        const icon = L.divIcon({
          html: iconHtml,
          className: 'bg-transparent',
          iconSize: [20, 20],
          iconAnchor: [10, 10]
        });

        const marker = L.marker(station.position, { icon });

        marker.on('click', (e) => {
          L.DomEvent.stopPropagation(e);
          onStationClick(station);
        });

        if (isSelected) {
           marker.setZIndexOffset(1000);
        }

        layerGroup.addLayer(marker);
      });
    }
  }, [viewState, currentStations, selectedStationId, onStationClick]);

  // Handle View Transitions
  useEffect(() => {
    if (!mapInstance.current) return;
    const map = mapInstance.current;

    if (viewState === ViewState.S0_CITY) {
      map.flyTo([22.65, 114.15], 10, { duration: 1.5 });
    } else if (viewState === ViewState.S1_DISTRICT && selectedDistrictId) {
      const district = DISTRICTS.find(d => d.id === selectedDistrictId);
      if (district) {
        map.flyTo(district.center, 13, { duration: 1.5 });
      }
    } else if (viewState === ViewState.S2_STATION && selectedStationId) {
      const station = currentStations.find(s => s.id === selectedStationId);
      if (station) {
        map.flyTo(station.position, 15, { duration: 1.2 });
      }
    }
  }, [viewState, selectedDistrictId, selectedStationId, currentStations]);

  return (
    <div className="relative w-full h-full bg-slate-900 overflow-hidden rounded-xl border border-slate-700 shadow-inner group">

      {/* Map Container */}
      <div ref={mapContainer} className="w-full h-full z-0" />

      {/* --- TOP TIME WINDOW OVERLAY --- */}
      <div className="absolute top-6 left-1/2 -translate-x-1/2 z-[500] bg-slate-900/90 border border-slate-600 rounded-full p-1 shadow-2xl flex items-center backdrop-blur-md">
         {TIME_MODES.map((mode) => (
            <button
              key={mode.id}
              onClick={() => setTimeMode(mode.id)}
              className={`px-6 py-2 text-sm font-bold rounded-full transition-all duration-300 ${
                timeMode === mode.id
                  ? 'bg-gradient-to-r from-cyan-600 to-blue-600 text-white shadow-lg scale-105'
                  : 'text-slate-400 hover:text-white hover:bg-slate-800'
              }`}
            >
              {mode.label}
            </button>
         ))}
      </div>

      {/* Back Button */}
      {viewState !== ViewState.S0_CITY && (
        <button 
          onClick={onBack}
          className="absolute top-6 left-6 z-[500] bg-slate-800/90 text-white px-4 py-2 rounded-lg border border-slate-600 hover:bg-cyan-600 hover:border-cyan-500 transition-all flex items-center gap-2 shadow-lg"
        >
          <ArrowLeft size={16} />
          返回 {viewState === ViewState.S2_STATION ? '区域详情' : '全市总览'}
        </button>
      )}

      {/* Legend Overlay */}
      <div className="absolute top-6 right-6 z-[500] bg-slate-900/80 p-4 rounded-xl border border-slate-700 text-xs text-slate-300 backdrop-blur pointer-events-none select-none shadow-xl">
        <h4 className="mb-3 font-bold text-white border-b border-slate-700 pb-2 flex items-center gap-2">
           <Layers size={14}/> 图例说明
        </h4>
        <div className="space-y-2">
          <div className="flex items-center gap-2"><span className="w-2.5 h-2.5 rounded-full bg-cyan-500/50 border border-cyan-400"></span> 区域容量充足</div>
          <div className="flex items-center gap-2"><span className="w-2.5 h-2.5 rounded-full bg-cyan-500/20 border border-cyan-800"></span> 区域容量空闲</div>
          <div className="h-px bg-slate-700 my-1"></div>
          <div className="flex items-center gap-2"><span className="w-2.5 h-2.5 rounded-full bg-emerald-400"></span> 场站正常</div>
          <div className="flex items-center gap-2"><span className="w-2.5 h-2.5 rounded-full bg-amber-400"></span> 场站故障</div>
          <div className="flex items-center gap-2"><span className="w-2.5 h-2.5 rounded-full bg-slate-400"></span> 场站离线</div>
        </div>
      </div>

    </div>
  );
};

export default MapComponent;

