// Generate Mock Stations near District Center
export const generateStations = (districtId: string): Station[] => {
  const stations: Station[] = [];
  const district = DISTRICTS.find(d => d.id === districtId);
  if (!district) return [];

  const center = district.center;
  const count = 8 + Math.floor(Math.random() * 8); 

  for (let i = 0; i < count; i++) {
    // Generate random variance around center (approx +/- 0.03 deg) to stay within rough district bounds
    const lat = center[0] + (Math.random() - 0.5) * 0.06;
    const lng = center[1] + (Math.random() - 0.5) * 0.06;

    stations.push({
      id: `${districtId}-s-${i}`,
      districtId,
      name: `${district.name}充电站 #${i + 1}`,
      position: [lat, lng],
      type: Math.random() > 0.7 ? 'Dedicated' : Math.random() > 0.4 ? 'Public' : 'Private',
      status: Math.random() > 0.9 ? 'Offline' : Math.random() > 0.85 ? 'Faulty' : 'Operational',
      utilization: Math.floor(Math.random() * 100),
    });
  }
  return stations;
};

// Mock Chart Data Generators
export const generateTimeSeries = (points: number, base: number, variance: number) => {
  return Array.from({ length: points }, (_, i) => ({
    time: `${String(Math.floor(i / 4)).padStart(2, '0')}:${String((i % 4) * 15).padStart(2, '0')}`,
    value: Math.max(0, base + Math.sin(i * 0.2) * variance + (Math.random() - 0.5) * variance),
    value2: Math.max(0, base * 0.8 + Math.cos(i * 0.2) * variance), // Comparative series
    value3: Math.max(0, base * 1.2 - Math.sin(i * 0.2) * (variance / 2)), // Prediction/Limits
  }));
};

