  S2_STATION = 'STATION'
}

export enum TimeMode {
  HISTORY = 'HISTORY',
  CURRENT = 'CURRENT',
  PREDICTION = 'PREDICTION'
}

export interface District {
  id: string;
  name: string;
  center: [number, number]; 
