  }
  return stations;
};

// Mock Chart Data
export const generateTimeSeries = (points: number, base: number, variance: number) => {
  return Array.from({ length: points }, (_, i) => {
    // Make History, Current, Prediction visually distinct in data shape
    const trend = Math.sin(i * 0.25) * variance;
    return {
      time: `${String(Math.floor(i / 4)).padStart(2, '0')}:${String((i % 4) * 15).padStart(2, '0')}`,
      value: Math.max(0, base + trend + (Math.random() - 0.5) * (variance/2)), // Base Metric
      value2: Math.max(0, base * 0.6 + Math.cos(i * 0.25) * variance), // Comparative (e.g., Last Day)
      value3: Math.max(0, base * 1.1 + trend), // Prediction
    };
  });
};

