                    <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
                    <XAxis dataKey="time" tick={{fontSize: 8, fill: '#64748b'}} stroke="#475569" interval={5} />
                    <YAxis label={{ value: '负载(kW)', angle: -90, position: 'insideLeft', fill: '#64748b', fontSize: 8 }} tick={{fontSize: 8, fill: '#64748b'}} stroke="#475569" />
                    <ReTooltip contentStyle={{backgroundColor: '#0f172a', borderColor: '#334155', fontSize: '9px'}} itemStyle={{padding: 0}} />
                    <Area type="monotone" dataKey="value" stroke="#0ea5e9" strokeWidth={1.5} fill="url(#colorLoad)" />
                 </AreaChart>
               </ResponsiveContainer>
             </div>
           </div>

           {/* Chart B: Spot Market Price (24h) */}
           <div className="bg-slate-800/50 p-2 rounded-lg border border-slate-700 flex-1 flex flex-col min-h-0">
             <h3 className="text-[10px] font-bold text-slate-300 mb-1 flex items-center gap-2">
                <Zap size={10} className="text-amber-400"/> 现货市场电价
             </h3>
             <div className="flex-1 w-full min-h-0">
               <ResponsiveContainer width="100%" height="100%">
                 <LineChart data={SPOT_PRICE_DATA} margin={{top: 2, right: 0, left: -10, bottom: 0}}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#334155" vertical={false} />
                    <XAxis dataKey="time" tick={{fontSize: 8, fill: '#64748b'}} stroke="#475569" interval={5} />
                    <YAxis label={{ value: '元/kWh', angle: -90, position: 'insideLeft', fill: '#64748b', fontSize: 8 }} tick={{fontSize: 8, fill: '#64748b'}} stroke="#475569" domain={[0, 2]} />
                    <ReTooltip contentStyle={{backgroundColor: '#0f172a', borderColor: '#334155', fontSize: '9px'}} itemStyle={{padding: 0}} />
                    <Line type="stepAfter" dataKey="value" stroke="#f59e0b" strokeWidth={1.5} dot={false} />
                 </LineChart>
               </ResponsiveContainer>
             </div>
           </div>

        </div>
      </div>
    );
  }

  // S2: Dense Station Detail
  if (selectedStation) {
    const totalCost = selectedStation.fixedCost + selectedStation.operationalCost;

    return (
      <div className="flex flex-col h-full overflow-hidden">
        {/* Header Block - Fixed Height */}
        <div className="mb-2 bg-gradient-to-r from-slate-800 to-slate-900 p-3 rounded-lg border border-slate-700 shrink-0">
          <div className="flex justify-between items-start">
             <div>
               <h2 className="text-base font-bold text-white flex items-center gap-2">
                 {selectedStation.name}
                 <span className={`text-[10px] px-1.5 rounded border ${
                   selectedStation.revenueLevel === 'S' ? 'bg-rose-500/20 text-rose-300 border-rose-500' : 
                   'bg-cyan-500/20 text-cyan-300 border-cyan-500'
