  role: string;
  count: number;
  salary: number; // Monthly RMB
}

export interface Station {
  id: string;
  districtId: string;
  name: string;
  locationLabel: string; 
  position: [number, number]; 
  type: 'Public' | 'Private' | 'Dedicated';
  // Features
