  fixedCost: number; // Wan Yuan
  operationalCost: number; // Wan Yuan/Year
  parkingFee: number;
  serviceFee: number;
  hasGroundLock: boolean;
  groundLockCoverage: number; // %

  // Detailed Staff
  staffDetails: StaffRole[];

  piles: PileDetail[];
